"""
mkt-original | Leviticus | chapters 14–15
Run: python3 scripts/zc-original-leviticus-14-15-fill.py

Ch 14: Purification ritual for healed skin disease (metzora) — two-bird ceremony,
        hyssop, cedar, scarlet; 8-day re-entry; cleansing of afflicted houses.
Ch 15: Bodily discharge regulations — male chronic/incidental flows, emissions,
        female menstrual and irregular discharges; washing rites and offerings.
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    return json.loads(p.read_text()) if p.exists() else {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

DATA = {
  "14": {
    "1": "<p>YHWH spoke to Moses (<em>waydabber YHWH el-Moshe</em>) — the standard revelation formula that opens priestly legislation, grounding every ritual requirement in divine speech rather than cultural convention.</p>",
    "2": "<p><em>Zot tihyeh torat ha-metzora</em> — this shall be the law (<em>torah</em>) of the diseased person (<em>metzora</em>): the term <em>metzora</em> derives from <em>tzara'at</em>, a term covering a range of skin conditions, fungal infections of fabric and houses; it does not correspond precisely to modern clinical leprosy (Hansen's disease).</p>",
    "3": "<p>The priest (<em>kohen</em>) shall go out of the camp and examine (<em>yivsodu</em>) — the leper lived outside the camp (Lev 13:46); re-entry required priestly inspection. The priest goes <em>out</em> to the unclean person, initiating the cleansing rather than awaiting the healed person inside the sanctuary.</p>",
    "4": "<p>The priest shall command two living clean birds (<em>tsipporim hayyot tehorot</em>), cedar wood (<em>etz erez</em>), scarlet yarn (<em>sheni tola'at</em>), and hyssop (<em>ezov</em>) — four elements whose combination recurs in the red heifer purification (Num 19:6) and in the Passover blood-daubing (hyssop, Exod 12:22). The number two and the contrast between slaughter and release encode death-and-life symbolism.</p>",
    "5": "<p>One bird shall be slaughtered (<em>shachat</em>) over an earthen vessel (<em>keli cheres</em>) over running water (<em>mayim hayyim</em>) — living water (<em>hayyim</em> = flowing, living) is required for major purification rites (Lev 14:5,6,50-52; Num 19:17); stagnant water does not suffice. The earthen vessel catches the blood; the combination of blood and living water will recur in the second bird's release.</p>",
    "6": "<p>The priest shall take the live bird with the cedar wood, scarlet yarn, and hyssop and dip them together with the live bird in the blood of the bird slaughtered over the running water — all four elements are dipped together, uniting them in the sacrificial blood before the live bird's release. The ritual binds the two birds as a single symbolic unit: one dies, the other carries the cleansing blood away.</p>",
    "7": "<p>He shall sprinkle (<em>hizza</em>) seven times on the one being cleansed of the skin disease — seven sprinklings mark complete cleansing throughout Leviticus (cf. Lev 4:6; 14:27,51; 16:14,19; Num 19:4). The metzora who was declared unclean (Lev 13:3) is now declared clean (<em>tihar</em>) by the same priestly authority.</p>",
    "8": "<p>The one being cleansed shall wash (<em>kibbes</em>) his clothes, shave off all his hair (<em>gillach et-kol-se'aro</em>), and bathe in water (<em>rachatz bamayim</em>) — triple purification: laundering, shaving, immersion. The shaving is radical (<em>kol</em> = all his hair) to remove any residue of the affliction from hair follicles; he may then enter the camp but must remain outside his tent for seven days.</p>",
    "9": "<p>On the seventh day he shall shave all his hair again — head, beard, eyebrows, all hair (<em>kol-se'aro</em>): the repetition of full shaving on day 7 mirrors the seven-day isolation period. After the second shaving he washes his clothes and bathes; a new counting begins.</p>",
    "10": "<p>On the eighth day he shall take two male lambs without blemish (<em>kesavim temimim</em>) and one female lamb a year old (<em>kivisah achat bat-shenata temima</em>) and three tenths of an ephah of fine flour mixed with oil for a grain offering, and one log of oil — the eighth-day ceremony requires three animals plus grain and oil, one of the most elaborate re-entry offerings in Leviticus. The <em>log</em> is approximately 300ml.</p>",
    "11": "<p>The priest who cleanses (<em>ha-metaher</em>) shall set the man being cleansed and these offerings before YHWH at the entrance of the tent of meeting — the cleansed person appears before the sanctuary threshold. The priest who performs the cleansing is the same one who performed the diagnosis (ch 13), maintaining continuity of priestly authority throughout the process.</p>",
    "12": "<p>The priest shall take one of the male lambs and offer it as a guilt offering (<em>asham</em>) — the guilt offering precedes the sin offering (v.19) in this ritual, unusual because the metzora is not guilty of a specific violation; the <em>asham</em> here functions as reparation for the period of exclusion from sanctuary participation rather than for a definable sin.</p>",
    "13": "<p>He shall slaughter the lamb in the place where they slaughter the sin offering and the burnt offering, in the holy place (<em>ha-makom ha-qadosh</em>) — the guilt offering shares the slaughter location with the sin and burnt offerings (cf. Lev 6:25; 7:2), northeast of the altar (Lev 1:11). The blood handling will differ from the standard guilt offering.</p>",
    "14": "<p>The priest shall take some of the blood of the guilt offering, and the priest shall put it on the lobe of the right ear (<em>tenuch ozen-yemino</em>) of the one being cleansed, on the thumb of his right hand (<em>bohen yado ha-yemanit</em>), and on the big toe of his right foot (<em>bohen raglo ha-yemanit</em>) — the identical three-point anointing used for Aaron and his sons at ordination (Exod 29:20; Lev 8:23-24), applied here to a restored layperson. Ear, hand, foot = the person's hearing (obedience), action (work), and movement (walk) — the whole reoriented life consecrated by blood.</p>",
    "15": "<p>The priest shall then take some of the log of oil and pour it into the palm of his own left hand — the oil is poured into the priest's left palm and applied with the right finger; the separation of pouring and applying hands allows precise ritual control. The oil application follows the blood application on the same three points (vv.17-18), layering consecration over atonement.</p>",
    "16": "<p>The priest shall dip his right finger in the oil that is in his left hand and shall sprinkle some of the oil with his finger seven times before YHWH — seven oil sprinklings mirror the seven blood sprinklings of v.7; the completeness motif structures the entire cleansing. The sprinklings are directed toward YHWH (before the sanctuary) before the oil is applied to the person.</p>",
    "17": "<p>Some of the oil remaining in his hand the priest shall put on the lobe of the right ear of him who is being cleansed and on the thumb of his right hand and on the big toe of his right foot — the blood of the guilt offering was applied first (v.14); now oil is placed on the same three points. The sequence blood-then-oil at ear/thumb/toe is identical to the ordination ceremony of Lev 8:23-30, where blood was applied first and then ordination oil.</p>",
    "18": "<p>And the rest of the oil that is in the priest's hand he shall put on the head of him who is being cleansed — the oil remaining after the three-point application is poured over the head, an act of anointing (<em>mashach</em>). The restored leper receives the same anointing gesture as priests and kings, marking restoration to full covenant membership.</p>",
    "19": "<p>Then the priest shall offer the sin offering (<em>asham</em> → should be <em>chatat</em>) and make atonement (<em>kipper</em>) for the one being cleansed from his uncleanness — the sin offering follows the guilt offering, completing the two-phase atonement. The Hebrew <em>kipper</em> (to atone, cover, ransom) is the central theological term of Levitical sacrifice; here it specifically covers the uncleanness (<em>tum'ato</em>) of the skin disease.</p>",
    "20": "<p>And the priest shall offer the burnt offering (<em>olah</em>) and the grain offering (<em>minchah</em>) on the altar — the culminating burnt offering (complete consecration) and grain offering (dedication of produce/life) complete the re-entry sequence. After this the person is fully clean (<em>taher</em>) and restored to normal Israelite life.</p>",
    "21": "<p>But if he is poor (<em>dal</em>) and cannot afford so much, he shall take one male lamb as a guilt offering to be waved, to make atonement for him — the poverty provision reduces the offering from three animals to one lamb plus two birds (vv.21-22). The guilt offering lamb is non-negotiable; the sin and burnt offerings may be replaced by turtledoves or pigeons. The essential atoning mechanism is preserved while the financial burden is reduced.</p>",
    "22": "<p>And two turtledoves (<em>shtei torim</em>) or two pigeons (<em>shtei vnei yona</em>), such as he can afford — the poor person's two birds replace the two additional lambs of vv.10-20. Turtledoves and pigeons are the standard poor-person's offering throughout Leviticus (Lev 1:14; 5:7,11; 12:8); Luke 2:24 records that Mary and Joseph brought this offering at Jesus's presentation, indicating their modest means.</p>",
    "23": "<p>He shall bring them on the eighth day for his cleansing to the priest, to the entrance of the tent of meeting before YHWH — the eighth-day timing is identical for rich and poor; the difference is only in the animals brought. The threshold of the tent of meeting is the liminal space where human uncleanness meets divine holiness for priestly mediation.</p>",
    "24": "<p>The priest shall take the lamb of the guilt offering and the log of oil, and the priest shall wave them as a wave offering before YHWH — waving (<em>tenupha</em>) consecrates the offering by presenting it before YHWH and receiving it back as a priestly portion (Lev 7:30-34). The lamb is waved while still alive before slaughter.</p>",
    "25": "<p>He shall slaughter the lamb of the guilt offering, and the priest shall take some of the blood of the guilt offering and put it on the lobe of the right ear of him who is being cleansed and on the thumb of his right hand and on the big toe of his right foot — the three-point blood application is identical for rich and poor (cf. v.14), preserving the full symbolic significance regardless of economic status. The ritual form of restoration is equal even if the materials differ.</p>",
    "26": "<p>The priest shall pour some of the oil into the palm of his own left hand — the oil ceremony is identical to the wealthy person's ceremony (v.15); the poverty provision changes only the animal offerings, not the oil application. The layered symbolism of blood-at-three-points then oil-at-three-points is preserved in full.</p>",
    "27": "<p>And the priest shall sprinkle with his right finger some of the oil that is in his left hand seven times before YHWH — seven sprinklings for the poor as for the wealthy; the completeness of the cleansing is not diminished by economic circumstances. The equality of access to full atonement is built into the structure of Levitical provision.</p>",
    "28": "<p>And the priest shall put some of the oil that is in his hand on the lobe of the right ear of him who is being cleansed, on the thumb of his right hand and on the big toe of his right foot, in the place where the blood of the guilt offering was put — the phrase <em>al-meqom ha-dam</em> (in the place of the blood) indicates that oil is applied precisely over the blood points, sealing or layering consecration upon atonement.</p>",
    "29": "<p>And the rest of the oil that is in the priest's hand he shall put on the head of him who is being cleansed, to make atonement for him before YHWH — the head anointing concludes both the wealthy and the poor person's restoration ceremony identically. The formula <em>lekhapper alav lifney YHWH</em> (to make atonement for him before YHWH) confirms the legal and relational restoration.</p>",
    "30": "<p>He shall also offer one of the turtledoves or pigeons, whichever he can afford — the poor person's sin offering and burnt offering (vv.30-31) replace the lambs of vv.19-20; the two birds serve double duty as both sin offering and burnt offering, one for each.</p>",
    "31": "<p>Such as he can afford, the one as a sin offering and the other as a burnt offering, along with the grain offering — the grain offering is mentioned here (cf. v.21: three tenths of an ephah with oil); no reduction is specified for the poor person's grain offering, though the proportion to the reduced animal offering may implicitly differ.</p>",
    "32": "<p>This is the law for him in whom is a case of leprous disease, who cannot afford the offerings for his cleansing — the section closes with a summary formula (<em>zot torat asher-bo nega tzara'at</em>), marking the end of the metzora purification laws and the provision for the poor as an integrated unit of legislation.</p>",
    "33": "<p>YHWH spoke to Moses and Aaron — both Moses and Aaron are addressed (cf. Lev 11:1; 13:1) when legislation concerns matters in which Aaron's priestly role is distinct from Moses's prophetic role. The house-plague legislation requires both the prophetic word and the priestly action.</p>",
    "34": "<p>When you come into the land of Canaan, which I give to you for a possession, and I put a case of leprous disease (<em>nega tzara'at</em>) in a house in the land of your possession — the house-plague legislation is prospective, applying only after settlement in Canaan. The phrase <em>ve-natati</em> (I put) is theologically striking: YHWH is the agent who places the affliction in the house, making the house-cleansing a divine visitation requiring priestly diagnosis rather than a routine maintenance issue.</p>",
    "35": "<p>Then he who owns the house shall come and tell the priest, 'There seems to me to be some kind of disease in my house' — the homeowner uses the cautious <em>ka-nega</em> (like a disease), maintaining epistemic humility before the official priestly determination. The obligation to report to the priest, not to remedy the situation independently, reflects the priestly monopoly on purity determinations.</p>",
    "36": "<p>The priest shall command that they empty the house before the priest goes in to examine the disease — emptying the house before inspection protects household goods from the mass declaration of impurity that would result if the priest diagnosed the house as diseased while contents were still inside. The protection of the household's material goods reflects pastoral concern within the purity system.</p>",
    "37": "<p>And he shall examine the disease. And if the disease is in the walls of the house with greenish or reddish spots (<em>yeraqqraqot o adamdammot</em>), and if they appear to be deeper than the surface — the diagnostic criteria parallel the skin disease criteria of Lev 13: color abnormality (greenish-reddish) plus apparent depth. The repetition of the same diagnostic logic for houses as for persons reflects a holistic purity theology in which the land, houses, and persons share the same vulnerability to <em>tzara'at</em>.</p>",
    "38": "<p>Then the priest shall go out of the house to the door of the house and shut up the house seven days — the house is quarantined exactly as a person with an ambiguous skin condition (Lev 13:4,5,21,26,31), with a seven-day isolation period before reinspection. The structural parallelism between person-quarantine and house-quarantine shows that <em>tzara'at</em> is understood as a single category of affliction affecting different substrates.</p>",
    "39": "<p>And the priest shall come again on the seventh day and look — the identical re-examination protocol applies to houses as to persons; if the disease has spread (<em>paroh ha-nega</em>) in the walls, it is malignant (<em>tzara'at memaheret</em> in v.44, 'spreading tzara'at').</p>",
    "40": "<p>Then the priest shall command that they take out the stones in which is the disease and throw them into an unclean place outside the city — removal of diseased stones is the architectural equivalent of shaving hair from an afflicted person; isolating and disposing of the diseased material removes the source. The unclean place outside the city maintains spatial separation of impurity from the community.</p>",
    "41": "<p>He shall have the inside of the house scraped all around (<em>ve-et-ha-bayit yiqtzeh misviv</em>) — scraping the interior walls removes potentially infected plaster, just as shaving hair removes potentially infected tissue. The scraped material is disposed of in the unclean place outside the city along with the diseased stones.</p>",
    "42": "<p>And they shall take other stones and put them in the place of those stones, and he shall take other plaster and plaster the house — replacement of diseased stones and replastering gives the house a chance at restoration; the new materials provide a clean substrate for reinspection. If the disease returns in the new materials (v.43-44), the house is declared incurably diseased.</p>",
    "43": "<p>If the disease breaks out again in the house, after he has taken out the stones and scraped the house and plastered it — if the disease returns after remediation, the judgment is that it has entered the structure itself; the house is declared irremediably impure. The recurrence after treatment is the decisive diagnostic criterion, paralleling the skin disease recurrence criterion of Lev 13:7.</p>",
    "44": "<p>Then the priest shall come and look, and if the disease has spread in the house, it is a malignant leprous disease (<em>tzara'at memaheret hi</em>) — <em>memaheret</em> (spreading, persistent) is the term for active, spreading, incurable tzara'at; the house is declared unclean (<em>tamei</em>) with the same finality as an incurably diseased person (Lev 13:11).</p>",
    "45": "<p>He shall break down the house, its stones and timber and all the plaster of the house, and he shall carry them outside the city to an unclean place — complete demolition is the house's equivalent of the metzora's permanent exclusion from the camp (Lev 13:46). The materials (stones, wood, plaster) are all carried to the unclean place; nothing is salvaged from an incurably diseased house.</p>",
    "46": "<p>Moreover, whoever enters the house while it is shut up shall be unclean until the evening — even during the quarantine period (before any diagnosis), entering the sealed house transmits impurity until evening. The house's impurity is contagious during the ambiguous period, not only after diagnosis.</p>",
    "47": "<p>And whoever sleeps in the house shall wash his clothes, and whoever eats in the house shall wash his clothes — lying in the house (prolonged exposure) and eating in the house (intimate association) create a higher degree of contact requiring laundering, while simple entry requires only sunset purification. The degree of impurity correlates with degree of contact.</p>",
    "48": "<p>But if the priest comes and looks, and if the disease has not spread in the house after the house was plastered, the priest shall pronounce the house clean, for the disease is healed (<em>nirpa ha-nega</em>) — the same verb <em>rapha</em> (heal, repair) is used for the house as for persons; the house 'healed' is language that treats the house as a living entity susceptible to healing as well as affliction.</p>",
    "49": "<p>For the cleansing of the house he shall take two small birds, cedar wood, scarlet yarn, and hyssop — the same four-element combination used for the human metzora's cleansing ceremony (v.4); the structural parallelism is complete: the same ritual cleanses both afflicted persons and afflicted houses, affirming the underlying unity of the tzara'at category.</p>",
    "50": "<p>He shall kill one of the birds in an earthen vessel over running water — the two-bird ceremony proceeds identically for the house as for the person (cf. vv.5-7): one bird slaughtered over living water in an earthen vessel, one bird dipped in the blood and released.</p>",
    "51": "<p>He shall take the cedar wood and the hyssop and the scarlet yarn, along with the live bird, and dip them in the blood of the bird that was killed and in the running water and sprinkle the house seven times — seven sprinklings for the house (as for the person, v.7). The live bird will carry the blood-mixture away when released, symbolically transferring the impurity out of the community.</p>",
    "52": "<p>Thus he shall cleanse the house with the blood of the bird and with the running water and with the live bird and with the cedar wood and hyssop and scarlet yarn — the summary names all five elements of the cleansing medium: blood, water, live bird, cedar, hyssop + scarlet. The combination of blood and water recurs throughout Leviticus and NT typology as the complete cleansing medium.</p>",
    "53": "<p>He shall let the live bird go out of the city into the open country (<em>el-mul panei ha-sadeh</em>). So he shall make atonement for the house, and it shall be clean — the bird's release into the open field (as in v.7 for the metzora) carries the cleansed impurity away from the community permanently. The language of atonement (<em>kipper</em>) is applied to the house, not just its inhabitants.</p>",
    "54": "<p>This is the law for every case of leprous disease (<em>nega tzara'at</em>): for an itch (<em>netek</em>) — <em>netek</em> is the scalp/beard condition of Lev 13:29-37, included here in the summary list.</p>",
    "55": "<p>For leprous disease in a garment or in a house — the summary (vv.54-57) explicitly names garment-tzara'at (Lev 13:47-59) and house-tzara'at (14:33-53) as subcategories under the single <em>torah ha-tzara'at</em>, confirming that all three substrates (person, fabric, architecture) are governed by a unified purity theology.</p>",
    "56": "<p>And for a swelling (<em>se'et</em>) and a scab (<em>sapachat</em>) and a shiny spot (<em>baheret</em>) — three surface anomalies first defined in Lev 13:2 that serve as the diagnostic criteria for human tzara'at; their inclusion in the closing summary ties chs 13–14 together as a coherent legal unit.</p>",
    "57": "<p>To teach when something is unclean and when it is clean (<em>lehorot beyom hatamei uveyon hatahor</em>) — the explicit pedagogical function of the entire tzara'at legislation: to teach the distinction between <em>tamei</em> and <em>tahor</em>, unclean and clean. This closing formula articulates what Leviticus 10:10 states as the priest's fundamental duty: to distinguish holy from common and unclean from clean.</p>"
  },
  "15": {
    "1": "<p>YHWH spoke to Moses and Aaron — both Moses and Aaron are addressed because the discharge legislation (Lev 15) involves priestly oversight of offerings (vv.14-15,29-30) and priestly protection from defilement (v.31); it is both prophetic legislation and priestly practice.</p>",
    "2": "<p>Speak to the people of Israel and say to them, when any man has a discharge from his body (<em>zov mibsaro</em>), his discharge is unclean — <em>zov</em> (flow, discharge) is the root term for the entire chapter; the <em>zav</em> (man with chronic discharge) and <em>zavah</em> (woman with irregular discharge) are named after it. The discharge renders the man (<em>zav</em>) himself impure, not merely the discharge substance.</p>",
    "3": "<p>And this is the law of his uncleanness for a discharge: whether his body runs with his discharge, or his body is blocked up by his discharge, it is his uncleanness — the distinction between a running (chronic, active) discharge and a blocked one suggests both acute and chronic presentations of the condition; both create the same degree of impurity in the person himself.</p>",
    "4": "<p>Every bed on which the one with the discharge lies shall be unclean, and everything on which he sits shall be unclean — contact impurity spreads from the <em>zav</em> to surfaces he lies or sits on, creating a secondary level of impurity that contaminates anyone who subsequently contacts those surfaces (v.5). The impurity radiates outward from the person through physical contact points.</p>",
    "5": "<p>And anyone who touches his bed shall wash his clothes and bathe himself in water and be unclean until the evening — the standard purification formula: laundering + immersion + sunset. The <em>erev</em> (evening) boundary marks the natural daily reset point in the Israelite purity system; all contact impurities of ordinary persons resolve by sunset after purification.</p>",
    "6": "<p>And whoever sits on anything on which the one with the discharge has sat shall wash his clothes and bathe in water and be unclean until the evening — secondary contact (sitting where the zav sat) creates the same temporary impurity as direct contact. The transmission chain: zav → surface → person → until-evening impurity.</p>",
    "7": "<p>And whoever touches the body of the one with the discharge shall wash his clothes and bathe in water and be unclean until the evening — direct body contact with the <em>zav</em> also creates until-evening impurity with standard purification. The categories of contact in vv.4-12 systematically cover: his bed, his seat, his body, his spittle, anything he rides, anything he touches, anything under him.</p>",
    "8": "<p>And if the man with the discharge spits on someone who is clean, then he shall wash his clothes and bathe in water and be unclean until the evening — saliva from the <em>zav</em> transmits impurity; the specific mention of spitting indicates that any bodily emission from the <em>zav</em> can create contact impurity, not only the discharge itself.</p>",
    "9": "<p>And any saddle on which the one with the discharge rides shall be unclean — the saddle (or riding apparatus) is treated like a sitting surface (v.6); a riding animal's saddle contacts both the animal and the rider in extended proximity, warranting specific inclusion alongside beds and seats.</p>",
    "10": "<p>And whoever touches anything that was under him shall be unclean until the evening. And whoever carries such things shall wash his clothes and bathe in water and be unclean until the evening — carrying objects that were under the <em>zav</em> creates a higher degree of contact than merely touching them, warranting laundering in addition to bathing; the distinction between touching and carrying reflects graduated impurity transmission based on degree of contact.</p>",
    "11": "<p>Anyone whom the one with the discharge touches without having rinsed his hands in water shall wash his clothes and bathe in water and be unclean until the evening — if the <em>zav</em> has not washed his hands, touching another person transmits impurity; if he has washed his hands, touching does not transmit impurity. Hand-washing provides a practical limiter on the <em>zav</em>'s social interaction, enabling some normal social life during the period of discharge.</p>",
    "12": "<p>And an earthen vessel that the one with the discharge touches shall be broken, and every vessel of wood shall be rinsed with water — earthenware cannot be purified (Lev 11:33; 6:28; 15:12) and must be destroyed; wooden vessels can be rinsed and remain in use. The distinction between earthenware and wood in impurity purifiability is a consistent principle throughout Leviticus (cf. Lev 11:32-35).</p>",
    "13": "<p>And when the one with a discharge is cleansed of his discharge, then he shall count for himself seven days for his cleansing, and wash his clothes. And he shall bathe his body in running water (<em>mayim hayyim</em>) and shall be clean — the chronic discharge requires seven clear days after cessation before purification is possible; running water (<em>hayyim</em>, living/flowing) is required for the <em>zav</em>'s purification as for the metzora's (Lev 14:5-6), a higher standard than still water. The seven-day waiting period confirms that the discharge has truly ended.</p>",
    "14": "<p>And on the eighth day he shall take two turtledoves or two pigeons and come before YHWH to the entrance of the tent of meeting and give them to the priest — the eighth-day offering mirrors the metzora's eighth-day re-entry (Lev 14:10-20,23); both conditions require sacrifice on the day after a seven-day purification period. The two birds (one sin offering, one burnt offering, v.15) restore full sanctuary access.</p>",
    "15": "<p>And the priest shall use them, one for a sin offering and the other for a burnt offering. And the priest shall make atonement for him before YHWH for his discharge — the atonement formula (<em>kipper alav lifney YHWH</em>) for discharge, as for tzara'at, skin disease, and childbirth (Lev 12:7-8), indicates that these conditions are not treated as purely physical matters but as states requiring priestly intercession and sacrificial restoration.</p>",
    "16": "<p>If a man has an emission of semen (<em>shichvat-zera</em>), he shall bathe his whole body in water and be unclean until the evening — incidental semen emission (not the chronic condition of the <em>zav</em>) creates only until-evening impurity after bathing, without requiring the seven-day waiting period or the eighth-day sacrifice. The proportional response: chronic discharge → 7 days + offering; incidental emission → until evening + bathing.</p>",
    "17": "<p>And every garment and every skin on which the semen comes shall be washed with water and be unclean until the evening — the semen-stained garment or leather article requires laundering; the impurity affects objects as well as the person, but with the same minimal duration (until evening).</p>",
    "18": "<p>If a man lies with a woman and has an emission of semen, both of them shall bathe themselves in water and be unclean until the evening — sexual intercourse creates mutual until-evening impurity for both partners, requiring bathing for both. This provision is not a moral judgment on marital intercourse but a purity regulation that creates a temporary, resolvable state requiring the same basic purification.</p>",
    "19": "<p>When a woman has a discharge, and the discharge in her body is blood (<em>vedam yihyeh zova bivisra</em>), she shall be in her menstrual impurity (<em>niddatah</em>) for seven days — the woman's normal menstrual flow creates the <em>niddah</em> state for seven days; anyone who touches her is unclean until evening (v.19b). The term <em>niddah</em> (separation, impurity) names the state the woman enters during menstruation.</p>",
    "20": "<p>And everything on which she lies during her menstrual impurity shall be unclean. Everything also on which she sits shall be unclean — the <em>niddah</em> woman's bed and seat become secondary impurity sources, identical to the <em>zav</em>'s furniture (vv.4-6); the structural parallel between male and female discharge impurity is intentional, treating both conditions under a unified framework.</p>",
    "21": "<p>And whoever touches her bed shall wash his clothes and bathe in water and be unclean until the evening — contact with the <em>niddah</em> woman's bed creates the standard until-evening impurity with laundering + bathing, identical to contact with the <em>zav</em>'s bed (v.5).</p>",
    "22": "<p>And whoever touches anything on which she sits shall wash his clothes and bathe in water and be unclean until the evening — the systematic coverage of bed and seat for the <em>niddah</em> parallels the coverage for the <em>zav</em> (vv.5-6); the parallel legislation reflects deliberate structural symmetry, not two separate traditions merged together.</p>",
    "23": "<p>Whether it is the bed or anything on which she sits, when he touches it he shall be unclean until the evening — the summary generalizes from the specific examples; all surfaces on which the <em>niddah</em> has lain or sat create contact impurity. The evening boundary applies universally to this category of secondary contact impurity.</p>",
    "24": "<p>And if any man lies with her and her menstrual impurity comes upon him (<em>vetihyeh niddatah alav</em>), he shall be unclean seven days, and every bed on which he lies shall be unclean — sexual intercourse during the <em>niddah</em> period creates a seven-day impurity for the man (not merely until-evening), and his bed becomes an impurity source during that period. Intercourse during niddah is treated more seriously than contact with niddah furniture.</p>",
    "25": "<p>If a woman has a discharge of blood for many days, not at the time of her menstrual impurity, or if she has a discharge beyond the time of her impurity, all the days of the discharge she shall continue in uncleanness — the irregular or prolonged discharge beyond the normal menstrual period creates an extended impurity state. The woman of Mark 5:25-34 (who had a flow of blood for twelve years) would have been in continuous <em>niddah</em> impurity under this provision throughout the twelve years, excluded from temple participation and making her contact with Jesus culturally transgressive.</p>",
    "26": "<p>Every bed on which she lies, all the days of her discharge, shall be to her as the bed of her menstrual impurity, and everything on which she sits shall be unclean, as the uncleanness of her menstrual impurity — the <em>zavah</em> (woman with irregular discharge) generates the same secondary impurity as the <em>niddah</em> throughout the entire period of the discharge, which may extend indefinitely. Every day of discharge creates the same contamination of her sleeping and sitting surfaces.</p>",
    "27": "<p>Whoever touches these things shall be unclean, and shall wash his clothes and bathe in water and be unclean until the evening — contact with the <em>zavah</em>'s furniture creates the same until-evening impurity as contact with <em>niddah</em> furniture (vv.21-22). The transmission rules for irregular discharge match those for normal menstruation.</p>",
    "28": "<p>But if she is cleansed of her discharge, she shall count for herself seven days, and after that she shall be clean — as with the <em>zav</em> (v.13), the <em>zavah</em> must count seven clear days after the discharge ends before she can be pronounced clean; the symmetry between male and female chronic discharge legislation is complete. After the seven days she proceeds to the eighth-day offering (v.29).</p>",
    "29": "<p>And on the eighth day she shall take two turtledoves or two pigeons and bring them to the priest, to the entrance of the tent of meeting — the <em>zavah</em>'s eighth-day offering (two birds) mirrors the <em>zav</em>'s offering (v.14) exactly; both undergo identical restoration procedures. The turtledoves/pigeons are the standard provision for those who cannot afford larger animals.</p>",
    "30": "<p>And the priest shall use one for a sin offering and the other for a burnt offering. And the priest shall make atonement for her before YHWH for her unclean discharge — the atonement formula for the <em>zavah</em> is word-for-word identical to the formula for the <em>zav</em> (v.15), completing the structural symmetry of male and female discharge legislation.</p>",
    "31": "<p>Thus you shall keep the people of Israel separate from their uncleanness (<em>ve-hizzartem et-bney Yisra'el mituma'tam</em>), lest they die in their uncleanness by defiling my tabernacle (<em>mishkani</em>) that is in their midst — the stated purpose of the entire discharge legislation: separation from impurity prevents the death that occurs when uncleanness contacts the holy sanctuary. The tabernacle's presence among the people creates both the gift of divine nearness and the requirement of purity; the two are inseparable.</p>",
    "32": "<p>This is the law for him who has a discharge and for him who has an emission of semen, becoming unclean thereby — the closing summary of male discharge legislation: the <em>zav</em> (chronic discharge) and the man with semen emission are both included under <em>torat ha-zav</em>.</p>",
    "33": "<p>And for her who is unwell with her menstrual impurity and for anyone, male or female, who has a discharge, and for the man who lies with a woman who is unclean — the closing summary explicitly names: (1) the <em>niddah</em>, (2) any person with discharge regardless of sex, and (3) the man who has intercourse with a <em>niddah</em>. The final phrase <em>asher yishkav im-niddah</em> (who lies with a niddah) identifies this as a distinct category requiring its own mention in the summary, consistent with the elevated impurity level of v.24.</p>"
  }
}

def main():
    e = load_comm('mkt-original', 'leviticus')
    merge_comm(e, DATA)
    save_comm('mkt-original', 'leviticus', e)
    print('Leviticus 14-15 mkt-original written.')

if __name__ == '__main__':
    main()
